<?php
namespace App\Domain\Combat\Data;final class CombatEncounterResult {private $status;private $winner;private $roundsCount;private $participants;private $rounds;public function __construct($status,$winner,$count,array $participants,array $rounds){$this->status=$status;$this->winner=$winner;$this->roundsCount=$count;$this->participants=array_values($participants);$this->rounds=array_values($rounds);}public function status(){return$this->status;}public function winnerSideIdentifier(){return$this->winner;}public function roundsCount(){return$this->roundsCount;}public function participants(){return array_slice($this->participants,0);}public function rounds(){return array_slice($this->rounds,0);}public function participant($id){foreach($this->participants as $p)if($p->identifier()===$id)return$p;return null;}}
